import React, { useState, useRef, useEffect } from 'react';

export default function CustomSelect({ options, placeholder = "Select option...", multiple = false }) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [selected, setSelected] = useState(multiple ? [] : null);
  const [focusedIndex, setFocusedIndex] = useState(-1);

  const containerRef = useRef(null);
  const searchInputRef = useRef(null);

  const filteredOptions = options.filter(opt =>
    opt.label.toLowerCase().includes(searchQuery.toLowerCase())
  );

  useEffect(() => {
    if (isOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isOpen]);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleKeyDown = (e) => {
    if (!isOpen) {
      if (e.key === "Enter" || e.key === "ArrowDown") {
        setIsOpen(true);
        e.preventDefault();
      }
      return;
    }

    switch (e.key) {
      case "ArrowDown":
        setFocusedIndex(prev => (prev + 1) % filteredOptions.length);
        e.preventDefault();
        break;
      case "ArrowUp":
        setFocusedIndex(prev => (prev - 1 + filteredOptions.length) % filteredOptions.length);
        e.preventDefault();
        break;
      case "Enter":
        if (focusedIndex >= 0 && focusedIndex < filteredOptions.length) {
          selectOption(filteredOptions[focusedIndex]);
          e.preventDefault();
        }
        break;
      case "Escape":
        setIsOpen(false);
        e.preventDefault();
        break;
      default:
        break;
    }
  };

  const selectOption = (option) => {
    if (multiple) {
      if (selected.find(s => s.value === option.value)) {
        setSelected(selected.filter(s => s.value !== option.value));
      } else {
        setSelected([...selected, option]);
      }
    } else {
      setSelected(option);
      setIsOpen(false);
    }
    setSearchQuery("");
    setFocusedIndex(-1);
  };

  return (
    <div ref={containerRef} onKeyDown={handleKeyDown} className="relative w-80 text-sm">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between border border-gray-300 rounded-lg px-4 py-2 bg-white text-left focus:outline-none focus:ring-2 focus:ring-purple-500 shadow-sm"
      >
        <span className="truncate text-gray-700">
          {multiple
            ? (selected.length === 0 ? placeholder : selected.map(s => s.label).join(", "))
            : (selected ? selected.label : placeholder)
          }
        </span>
        <svg className="w-4 h-4 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {isOpen && (
        <div className="absolute z-10 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg overflow-hidden">
          <div className="p-2 border-b border-gray-100">
            <input
              ref={searchInputRef}
              type="text"
              placeholder="Search..."
              value={searchQuery}
              onChange={(e) => { setSearchQuery(e.target.value); setFocusedIndex(-1); }}
              className="w-full px-3 py-1.5 border border-gray-200 rounded-md focus:outline-none focus:ring-1 focus:ring-purple-500 text-sm"
            />
          </div>
          <ul className="max-h-60 overflow-y-auto">
            {filteredOptions.length === 0 ? (
              <li className="px-4 py-3 text-gray-400 text-center">No options found</li>
            ) : (
              filteredOptions.map((opt, idx) => {
                const isSelected = multiple
                  ? !!selected.find(s => s.value === opt.value)
                  : selected?.value === opt.value;
                const isFocused = focusedIndex === idx;

                return (
                  <li
                    key={opt.value}
                    onClick={() => selectOption(opt)}
                    className={`cursor-pointer px-4 py-2 flex items-center justify-between ${isFocused ? 'bg-purple-50 text-purple-700' : 'text-gray-700 hover:bg-gray-50'}`}
                  >
                    <span className={`block truncate ${isSelected ? 'font-semibold' : ''}`}>{opt.label}</span>
                    {isSelected && (
                      <svg className="w-4 h-4 text-purple-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                    )}
                  </li>
                );
              })
            )}
          </ul>
        </div>
      )}
    </div>
  );
}
